insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:7-1-final:learn:b9253656', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'learn', 'mcq', 1, '{"readingTitle": "Using Financial Information to Make Decisions", "reading": "<p>Businesses use financial information to <strong>measure performance</strong> and <strong>inform decisions</strong>. The most common types include:</p>\n        <ul>\n          <li><strong>Costs and Revenues:</strong> Knowing total costs versus total revenues shows whether the business is profitable.</li>\n          <li><strong>Gross and Net Profit:</strong> Gross profit shows the profit from sales before expenses; net profit shows profit after all costs are deducted.</li>\n          <li><strong>Profit Margins:</strong> Shows what percentage of revenue becomes profit — useful for comparing efficiency over time.</li>\n          <li><strong>Cash Flow:</strong> Shows the timing of money coming in and going out — a business can be profitable but still fail if cash runs out.</li>\n          <li><strong>Break-Even Analysis:</strong> Identifies the sales level at which the business covers all its costs — useful when launching a new product or making investment decisions.</li>\n          <li><strong>Average Rate of Return (ARR):</strong> Used to compare the profitability of different investment options.</li>\n        </ul>\n        <p><strong>For financial information to be useful, it must be:</strong></p>\n        <ul>\n          <li><strong>Accurate:</strong> Incorrect data leads to incorrect decisions and potential financial loss.</li>\n          <li><strong>Sufficient:</strong> There must be enough data to make a meaningful comparison.</li>\n          <li><strong>Up to Date:</strong> Outdated information may be irrelevant, especially if the market has changed significantly.</li>\n        </ul>\n        <div class=\"formula-box\">\n          <strong>Net Profit =</strong> Gross Profit &minus; Expenses (overheads)\n          <br><br>\n            <strong>Gross Profit =</strong> Revenue &minus; Cost of Sales\n            <br><br>\n              <strong>Net Profit Margin (%) =</strong> (Net Profit &divide; Revenue) &times; 100\n            </div>", "question": "According to this card, what does ''net profit margin'' show?", "options": ["What percentage of revenue becomes profit, useful for comparing efficiency", "The total amount of cash a business has in its bank account today", "The exact number of units a business must sell to break even", "The total revenue a business receives before any of its costs are deducted"]}'::jsonb, '{"answer": 0, "explain": "The card explains net profit margin shows what percentage of revenue becomes profit, useful for comparing a business''s efficiency over time."}'::jsonb),
('business:7-1-final:learn:79132d1e', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'learn', 'mcq', 1, '{"readingTitle": "Limitations of Financial Information", "reading": "<p>While financial information is essential, it has <strong>limitations</strong> that businesses must be aware of when making decisions.</p>\n              <ul>\n                <li><strong>Inflation:</strong> The Average Rate of Return (ARR) does not account for the effects of inflation on the value of money. £1 today is worth more than £1 in five years'' time — but ARR treats them the same.</li>\n                <li><strong>Historical Data:</strong> Financial accounts are published after the period they cover. A lot may have changed in the market by the time the data is analysed.</li>\n                <li><strong>Incomplete Picture:</strong> Financial data only measures what can be quantified in money. It cannot capture reputation, staff morale, brand loyalty or the external competitive environment.</li>\n                <li><strong>Comparability:</strong> Comparing accounts between businesses can be misleading if they use different accounting methods or operate in different markets.</li>\n              </ul>\n              <p>Businesses typically compare their accounts in two ways:</p>\n              <ul>\n                <li><strong>Year-on-Year:</strong> Comparing this year''s performance against previous years to identify trends.</li>\n                <li><strong>Against Competitors:</strong> Comparing with rivals (only possible for Limited Companies which must publish their accounts) to benchmark performance.</li>\n              </ul>", "question": "According to this card, what limitation does Average Rate of Return (ARR) have?", "options": ["It can only ever be calculated by limited companies, not other businesses", "It does not account for the effects of inflation on the value of money", "It ignores the cost of the original investment being compared", "It cannot be used to compare two different investment options at all"]}'::jsonb, '{"answer": 1, "explain": "The card explains ARR does not account for inflation — £1 today is worth more than £1 in five years'' time, but ARR treats them the same."}'::jsonb),
('business:7-1-final:learn:ff09324b', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'learn', 'mcq', 1, '{"readingTitle": "Synoptic Questions: How to Link Business Areas", "reading": "<p>The final 9-mark question on OCR Paper 2 is <strong>always synoptic</strong> — it requires you to link a topic from Component 01 (e.g. stakeholders, globalisation, environment) with a topic from Component 02 (e.g. cash flow, marketing mix, costs). Here is how to approach these questions:</p>\n              <ul>\n                <li><strong>The Change:</strong> This is the topic that \"makes something happen\" — e.g. a change in marketing, or a decision to go more environmentally friendly. Your Knowledge (K) and Understanding (U) marks come from explaining this topic.</li>\n                <li><strong>The Impact:</strong> This is what is affected — e.g. cash flow, operations, HR. Your Application (APP), Analysis (AN) and Evaluation (EVAL) marks come from explaining the impact on the specific business in the case study.</li>\n              </ul>\n              <div class=\"case-study-box\">\n                <h4>Example: Dog and Gun Inn (Cash Flow)</h4>\n                <p>The question asks: \"Evaluate the impact the <strong>change to marketing</strong> by the Dog and Gun Inn may have had on its <strong>cash flow</strong>.\"</p>\n                <p>&rarr; Knowledge/Understanding marks: define and explain <strong>marketing</strong>.<br>\n                  &rarr; Application/Analysis/Evaluation marks: explain how the specific marketing changes (takeaway menu, website adverts) would have affected the <strong>cash flow</strong> of the Dog and Gun specifically.</p>\n              </div>\n              <p>A common mistake is to write entirely about marketing and forget to link it back to the named impact (cash flow). Always keep asking yourself: <em>\"So what does this mean for the cash flow / costs / revenue of this specific business?\"</em></p>", "question": "According to this card, where do Application, Analysis and Evaluation marks come from in a synoptic question?", "options": ["Simply repeating the definition of the ''change'' topic several times over again here", "Describing the ''change'' topic in as much general detail as possible", "Explaining the impact on the specific business regarding the named ''affected'' topic", "Listing every possible business area without ever linking any of them together"]}'::jsonb, '{"answer": 2, "explain": "The card explains APP, AN and EVAL marks come from explaining the impact on the specific business regarding the named ''affected'' topic, such as cash flow."}'::jsonb),
('business:7-1-final:misc:10b9d76c', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write about ''interdependence'' as simply meaning ''businesses need each other'' or ''companies trade with each other.''</p><p><strong>✅ The correct idea:</strong> Interdependence in this context means the four FUNCTIONAL AREAS within a SINGLE business (marketing, HR, operations, finance) are linked. A decision in one internal area affects the others. It is NOT about businesses trading with each other.</p>", "question": "What does ''interdependence'' actually mean in this topic?", "options": ["Different businesses need each other and trade with one another", "A business depends entirely on its own direct competitors in order to succeed", "A business depends on customers trading with each other directly", "The four functional areas within a single business are linked to each other"]}'::jsonb, '{"answer": 3, "explain": "The card explains interdependence means the four functional areas within a SINGLE business are linked — it is not about businesses trading with each other."}'::jsonb),
('business:7-1-final:misc:aeeb2b62', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For the 3-mark analyse question, students describe what a function does generally (e.g. ''marketing involves promotion'') without linking it to the specific business in the case study.</p><p><strong>✅ The correct idea:</strong> The examiner''s report highlighted this was the most common reason for scoring zero. You MUST name a specific marketing activity (Understanding), THEN link it to the specific company named (Application), THEN explain the impact on the other function mentioned in the question (Analysis).</p>", "question": "Why does describing a function generally, e.g. ''marketing involves promotion'', score zero on a 3-mark analyse question?", "options": ["It fails to link the activity to the specific business named in the case study", "It is factually incorrect, since marketing never involves promotion at all", "It already contains full application and analysis in one short sentence", "It only applies to finance questions, and never to marketing questions"]}'::jsonb, '{"answer": 0, "explain": "The card explains this was the most common reason for scoring zero — you must name a specific activity, link it to the business, then explain the impact."}'::jsonb),
('business:7-1-final:misc:8b57b6bb', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse ''risk'' with only financial risk — they do not mention non-financial risks like stress, health issues or strained family relationships.</p><p><strong>✅ The correct idea:</strong> The specification explicitly identifies BOTH financial risk (losing money invested) AND non-financial risk (health, stress, damaged family relationships). For a question asking for two risks, one of each type is a strong answer.</p>", "question": "Does ''risk'' in this topic only refer to financial risk?", "options": ["Yes — only financial risk is ever recognised in this exam specification", "No — non-financial risks like stress and strained relationships also count", "Yes — but only health risks count as a form of financial risk", "No — but only because financial risk does not actually exist"]}'::jsonb, '{"answer": 1, "explain": "The card explains the specification identifies BOTH financial risk (losing invested money) AND non-financial risk (health, stress, damaged relationships)."}'::jsonb),
('business:7-1-final:misc:b810b613', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write that the limitation of ARR is that ''it is hard to calculate'' or ''businesses do not always have the right data.''</p><p><strong>✅ The correct idea:</strong> The official, examinable limitation of ARR is that it does NOT account for the effects of INFLATION on the value of money. Money received in the future is worth less in real terms than money received today — ARR ignores this.</p>", "question": "What is the official, examinable limitation of ARR, according to this card?", "options": ["It is too difficult for most businesses to actually calculate correctly", "Businesses never have the right data available to calculate it at all", "It does not account for the effects of inflation on the value of money", "It can only be used by businesses that have already made a profit"]}'::jsonb, '{"answer": 2, "explain": "The card explains the official limitation is that ARR ignores inflation — money received in the future is worth less in real terms than money today."}'::jsonb),
('business:7-1-final:misc:ba3a5a94', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For the 9-mark synoptic question, students focus entirely on the ''change'' topic (e.g. marketing) and forget to explain the impact on the ''affected'' topic (e.g. cash flow).</p><p><strong>✅ The correct idea:</strong> Your K and U marks come from explaining the ''change'' topic. But your APP, AN and EVAL marks ALL come from explaining the effect on the specific impact named in the question (e.g. cash flow, costs, revenues). You MUST switch focus to the impact in the second half of your answer.</p>", "question": "What mistake do students make when they focus entirely on the ''change'' topic in a 9-mark synoptic question?", "options": ["They correctly earn every single mark available for the whole question", "They accidentally answer a completely different question by mistake", "They spend too little time explaining what the ''change'' topic actually involves", "They forget to explain the impact on the ''affected'' topic named in the question"]}'::jsonb, '{"answer": 3, "explain": "The card explains APP, AN and EVAL marks all come from explaining the effect on the named ''affected'' topic — you must switch focus in the second half of the answer."}'::jsonb),
('business:7-1-final:misc:84751d1d', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse ''stakeholders'' with ''shareholders'' — they write an entire answer referring to ''stakeholders'' without ever naming a specific one.</p><p><strong>✅ The correct idea:</strong> To gain Application and Analysis marks in the 9-mark question about financial data and stakeholders, you MUST name specific stakeholders (e.g. employees, suppliers, banks, the local community). Vague references to ''stakeholders'' do not earn marks.</p>", "question": "What must students do to gain Application and Analysis marks about stakeholders?", "options": ["Name specific stakeholders, such as employees, suppliers, banks or the community", "Use only the general word ''stakeholders'' throughout the entire answer", "Refer only to shareholders, since stakeholders are never creditable at all here", "Avoid naming any stakeholder group at all in the final answer given"]}'::jsonb, '{"answer": 0, "explain": "The card explains you must name specific stakeholders like employees, suppliers or banks — vague references to ''stakeholders'' do not earn marks."}'::jsonb),
('business:7-1-final:misc:9e3752e6', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think profit and cash flow are the same thing — they use the terms interchangeably.</p><p><strong>✅ The correct idea:</strong> Profit is total revenue minus total costs over a period. Cash flow is the actual movement of money in and out of the business. A business can be profitable but still have a cash flow problem if customers have not yet paid their invoices.</p>", "question": "Are profit and cash flow the same thing that can be used interchangeably?", "options": ["Yes — profit and cash flow are simply two names for the same figure", "No — a business can be profitable but still have a cash flow problem", "Yes — but only if the business has already paid all of its invoices", "No — but only because cash flow is always higher than profit"]}'::jsonb, '{"answer": 1, "explain": "The card explains profit is revenue minus costs over a period, while cash flow is the actual movement of money — a business can be profitable yet still face a cash shortage."}'::jsonb),
('business:7-1-final:misc:84ed6de8', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked how a marketing decision affects operations, students write about marketing activities (e.g. ''they will advertise more'') rather than the impact on the operations/production function.</p><p><strong>✅ The correct idea:</strong> The examiner''s report noted this was very common. Once you have identified the marketing activity (for the Understanding mark), you MUST explain the consequence for the operations function specifically — e.g. ''this means operations will need to INCREASE PRODUCTION to meet higher demand.''</p>", "question": "When asked how a marketing decision affects operations, what must the answer explain?", "options": ["Only the marketing activities themselves, such as advertising more heavily", "A definition of operations with no link at all to the marketing decision", "The consequence for the operations function specifically, such as increased production", "The consequence for the finance function instead of the operations function itself"]}'::jsonb, '{"answer": 2, "explain": "The card explains you must explain the consequence for operations specifically — e.g. ''operations will need to increase production to meet higher demand.''"}'::jsonb),
('business:7-1-final:tips:cd020261', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Locked Gate: Understanding Opens Everything", "reading": "\n              <p>Every 3-mark Analyse question in this topic works the same way. There is a <strong>locked gate</strong> — you cannot earn any marks without first showing <strong>Understanding (U)</strong> of the key term in the question.</p>\n              <p><strong>The 3-step formula:</strong></p>\n              <ul>\n                <li><strong>Step 1 — Understanding (U):</strong> Explain what the function or concept DOES. Be specific. Name an activity it carries out.</li>\n                <li><strong>Step 2 — Application (APP):</strong> Link your understanding directly to the business in the case study. Use a specific detail from the text.</li>\n                <li><strong>Step 3 — Analysis (AN):</strong> Explain the impact — what happens as a result? This must be a business-facing consequence (e.g. production increases, costs rise, revenue falls).</li>\n              </ul>\n              <p><strong>❌ Bad Answer (0 marks):</strong><br />\n                <em>\"The finance function is important for BP because it manages the company''s finances efficiently.\"</em><br />\n                This is tautological — saying \"finance manages finances\" earns no understanding mark, and no further marks can follow.</p>\n              <p><strong>✅ Good Answer (3 marks):</strong><br />\n                <em>\"The finance function produces cash-flow forecasts and budgets (U) in order to inform BP''s managers how much money is available for investment into new technologies (APP), such as the wind farms being developed in America, meaning BP can make financially sound decisions to meet its sustainability objectives (AN).\"</em></p>\n              <p><strong>⚠️ Examiner Warning:</strong> On the real exam, two thirds of candidates scored zero on Q2 (Unilever, 3 marks) and the majority scored zero on Q4 (BP, 3 marks). The reason was identical in both cases: they failed to identify a specific activity of the named function. \"Marketing the product\" or \"managing the business efficiently\" are too vague and score nothing.</p>\n              ", "question": "According to this card, what happens if you don''t show Understanding first in a 3-mark analyse question?", "options": ["You can still earn full marks through Application and Analysis alone", "You automatically earn 2 out of 3 marks for the remaining two steps", "The examiner awards the mark anyway, provided the answer is detailed", "No further marks can follow, since Understanding is a locked gate"]}'::jsonb, '{"answer": 3, "explain": "The card describes Understanding as a ''locked gate'' — without it, no Application or Analysis marks can be awarded, no matter how good the rest of the answer is."}'::jsonb),
('business:7-1-final:tips:c6f44161', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks (Synoptic) — The Synoptic 9: Two Topics, One Answer", "reading": "\n              <p>The final 9-mark question always links <strong>two topics</strong>: one from Component 01 and one from Component 02. There are <strong>9 marks split across 5 skills</strong>: K (1) + U (1) + APP (2) + AN (2) + EVAL (3).</p>\n              <p><strong>The 4-paragraph structure:</strong></p>\n              <ul>\n                <li><strong>Paragraph 1 — K &amp; U:</strong> Define the ''change'' topic (K) and explain how it works (U). Keep this brief — it''s only 2 marks total.<br />\n                  <em>Starter: \"Marketing refers to [K]... This involves activities such as [U]...\"</em></li>\n                <li><strong>Paragraph 2 — APP &amp; AN (Point 1):</strong> Use ONE specific detail from the case study (APP) to explain ONE impact on the named affected area (AN).<br />\n                  <em>Starter: \"In the case of [Business Name], [specific detail from text] (APP)... As a result, this would [impact on the named area — cash flow / costs / revenues] (AN)...\"</em></li>\n                <li><strong>Paragraph 3 — APP &amp; AN (Point 2):</strong> Use a SECOND specific detail from the case study (APP) to explain a SECOND impact on the named affected area (AN).<br />\n                  <em>Starter: \"Furthermore, [second detail from text] (APP)... This means [second impact on the named area] (AN)...\"</em></li>\n                <li><strong>Paragraph 4 — EVAL (3 marks):</strong> Make a clear judgement (1 mark), justify it with context (1 mark), and add a conditional ''it depends on'' statement (1 mark).<br />\n                  <em>Starter: \"Overall, I believe [judgement] (EVAL). This is because [reason using case study context] (EVAL). However, this will ultimately depend on [a contextual condition, e.g. the size of the changes / whether customers continue to buy] (EVAL).\"</em></li>\n              </ul>\n              <p><strong>🚫 Critical Warning — Do NOT write evaluation in the wrong place.</strong> The three evaluation marks are ONLY awarded in the final judgement section. Writing \"I think this is good\" halfway through your analysis does not count as evaluation.</p>\n              <p><strong>⚠️ Examiner Warning:</strong> Many candidates wrote entirely about ''stakeholders'' without ever naming a specific one (e.g. employees, suppliers, banks). Vague references to ''stakeholders'' earned zero for application AND analysis. You must name them.</p>\n              ", "question": "According to this card, where are the three evaluation marks specifically awarded?", "options": ["Only in the final judgement section, not partway through the analysis", "Anywhere in the answer, as long as a personal opinion is expressed", "Only in the very first paragraph, before any analysis is given", "Automatically, regardless of where in the answer they are written"]}'::jsonb, '{"answer": 0, "explain": "The card warns evaluation marks are ONLY awarded in the final judgement section — writing ''I think this is good'' halfway through the analysis does not count."}'::jsonb),
('business:7-1-final:tips:68e6a921', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks (Pairs of linked questions) — Q16 Style: Same Business, Three Different Functions", "reading": "\n              <p>Some questions ask you to analyse the impact of the SAME thing (e.g. being environmentally friendly) on THREE DIFFERENT functions (marketing, HR, finance) in separate 3-mark questions. Each is marked independently using the same U &rarr; APP &rarr; AN structure.</p>\n              <p><strong>Key tip:</strong> Do NOT repeat the same point in each answer. Each response must show a different aspect of the same theme.</p>\n              <ul>\n                <li><strong>Marketing (3 marks):</strong> Focus on how the marketing mix changes — e.g. promotion changes to highlight eco-credentials, or product packaging changes.</li>\n                <li><strong>HR (3 marks):</strong> Focus on how staff are recruited, trained or managed differently — e.g. online interviews to reduce travel, remote working, new IT training.</li>\n                <li><strong>Finance (3 marks):</strong> Focus on costs, cash flow or sources of finance — e.g. higher costs from eco-friendly suppliers, need to monitor cash flow more carefully, may need an increased overdraft.</li>\n              </ul>\n              <p><strong>✅ Good Answer for Finance (3 marks):</strong><br />\n                <em>\"Being environmentally friendly is likely to increase operating costs (U) as NEXT plc. will need to source products from more expensive ethical/eco-friendly suppliers worldwide (APP). This means the finance department may face cash flow difficulties and need to apply for a larger bank overdraft to cover the shortfall (AN).\"</em></p>\n              ", "question": "According to this card, what must you avoid when analysing the same theme across three different functions?", "options": ["Using the U to APP to AN structure for each of the three separate answers", "Repeating the same point in each answer instead of a different aspect each time", "Discussing marketing, HR and finance as three genuinely separate business functions", "Writing three separate three-mark answers instead of one combined answer"]}'::jsonb, '{"answer": 1, "explain": "The card warns against repeating the same point in each answer — each response must show a different aspect of the same theme, marked independently."}'::jsonb),
('business:7-1-final:tips:06308eaf', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Make a Choice, Back It Up, Compare", "reading": "\n              <p>A 3-mark ''Recommend'' question (like Q16 iv) asks you to make a <strong>clear judgement</strong> about which option is most important or most affected. It is marked on three levels:</p>\n              <ul>\n                <li><strong>1 mark:</strong> A judgement with limited justification — you name a winner but don''t really explain why.</li>\n                <li><strong>2 marks:</strong> A judgement with good justification — you name a winner AND give a clear reason with some reference to relevant information.</li>\n                <li><strong>3 marks:</strong> A judgement with strong, detailed justification — you name a winner AND give a detailed, specific reason that shows clear appraisal of why this function is most affected compared to others.</li>\n              </ul>\n              <p><strong>✅ Good Answer (3 marks):</strong><br />\n                <em>\"The human resources function would be most affected by NEXT plc. being environmentally friendly (JUDGEMENT) because it would impact the way ALL of its workers are employed, trained and managed on a day-to-day basis (JUSTIFICATION). For example, NEXT would need to introduce new IT-based processes, mobile technologies and online training packages to reduce its carbon footprint across its entire workforce (STRONG CONTEXTUAL DETAIL).\"</em></p>\n              ", "question": "According to this card, what separates a 3-mark recommend answer from a 1-mark answer?", "options": ["Simply naming a winner, without giving any reason for the choice made", "Writing a much longer answer overall, regardless of its actual content", "Detailed, specific justification showing clear appraisal, not just a named winner", "Avoiding any reference at all to the specific business that is named in the question"]}'::jsonb, '{"answer": 2, "explain": "The card explains a 3-mark answer needs detailed, specific justification showing clear appraisal, while a 1-mark answer just names a winner with limited justification."}'::jsonb),
('business:7-1-final:tips:d61e9121', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'tips', 'mcq', 1, '{"readingTitle": "State / Identify — 1–2 marks — Precision Over Paragraphs", "reading": "\n              <p>For 1-mark ''State'' or ''Identify'' questions, one precise point earns the full mark. Do NOT write paragraphs — it wastes time and the examiner is only looking for a single correct statement.</p>\n              <p><strong>The Formula:</strong></p>\n              <ul>\n                <li>One clear, specific, relevant point = 1 mark ✅</li>\n                <li>A vague, general statement = 0 marks ❌</li>\n              </ul>\n              <p><strong>❌ Bad Answer (0 marks) for \"Identify two variable costs\":</strong><br />\n                <em>\"Production costs and salaries.\"</em><br />\n                \"Salaries\" are a <strong>fixed</strong> cost, not variable. \"Production costs\" is too vague.</p>\n              <p><strong>✅ Good Answer (2 marks):</strong><br />\n                <em>\"1. Raw materials / cost of sales. 2. Packaging.\"</em></p>\n              <p><strong>⚠️ Examiner Warning on Variable Costs:</strong> Do NOT accept ''salaries'' — these are fixed costs. The mark scheme specifically excludes this. Only accept wages (which can vary with hours worked), raw materials, packaging and stock/components.</p>\n              ", "question": "According to this card, why would ''salaries'' be rejected as an answer to ''identify a variable cost''?", "options": ["Salaries are not a real business cost recognised in this exam specification", "Salaries only ever apply to businesses with more than one employee", "Salaries are classed as a form of revenue, not a cost, in this topic", "Salaries are a fixed cost, not a variable one, according to the mark scheme"]}'::jsonb, '{"answer": 3, "explain": "The card''s examiner warning states salaries are a fixed cost — the mark scheme specifically excludes them from being accepted as a variable cost."}'::jsonb),
('business:7-1-final:tips:5b5f012c', 'business', 'business:7-1-final', '7.1 Interdependent Nature of Business', 'tips', 'mcq', 1, '{"readingTitle": "Calculate — 3 marks — Show Your Workings Every Time", "reading": "\n              <p>For calculation questions, you must <strong>always show your workings</strong> — even if you get the final answer wrong, you can still earn marks for correct method.</p>\n              <p><strong>Net Profit Calculation (3 marks) — The Two-Step Method:</strong></p>\n              <ul>\n                <li><strong>Step 1 — Calculate Gross Profit (1 mark):</strong> Revenue &minus; Cost of Sales</li>\n                <li><strong>Step 2 — Calculate Net Profit (2 marks):</strong> Gross Profit &minus; All Other Expenses (Salaries + Rent + Other expenses)</li>\n              </ul>\n              <p><strong>Example (RCP Question):</strong></p>\n              <ul>\n                <li>Gross Profit = £2,000,000 &minus; £500,000 = <strong>£1,500,000</strong> (1 mark)</li>\n                <li>Total Expenses = £1,300,000 + £100,000 + £50,000 = £1,450,000</li>\n                <li>Net Profit = £1,500,000 &minus; £1,450,000 = <strong>£50,000</strong> (2 marks)</li>\n              </ul>\n              <p><strong>Net Profit Margin</strong> = (£50,000 &divide; £2,000,000) &times; 100 = <strong>2.5%</strong></p>\n              <p><strong>⚠️ Warning:</strong> If you only write the final answer with no workings and it is wrong, you score zero. With workings shown, even a mathematical error in the final step earns 2 out of 3 marks.</p>\n              ", "question": "According to this card, what happens if you write only the final answer with no workings and it is wrong?", "options": ["You score zero, since there is no method shown to award partial credit", "You still score full marks, since only the final answer is ever checked", "You automatically score 2 out of 3 marks regardless of the final answer", "The examiner estimates your workings and awards marks accordingly"]}'::jsonb, '{"answer": 0, "explain": "The card warns that with no workings shown, a wrong final answer scores zero — but with workings shown, even a mathematical error can earn 2 out of 3 marks."}'::jsonb),
